calcFn:
var vol, f3Info;
    if (boxType === 'sealed') {
      vol = vas * Math.pow(qts, 2.87) * 0.7;
      var qtc = 0.707;
      f3Info = 'F3 ≈ ' + fmt(42 * Math.pow(12 / driverSize, 0.8) / qtc, 0) + ' Hz (Butterworth alignment)';
    } else {
      vol = vas * 1.0;
      var fb = 28 * Math.pow(12 / driverSize, 0.5);
      var portDia = driverSize * 0.4;
      var portLen = (23562 * portDia * portDia) / (vol * 1000 * fb * fb) - 0.825 * portDia;
      f3Info = 'Tune: ' + fmt(fb, 0) + ' Hz | Port: ' + fmt(portDia, 1) + '" dia × ' + fmt(Math.abs(portLen), 1) + '" long';
    }
    var volCuFt = vol / 28.317;
    var side = Math.pow(vol * 1000, 1/3) / 10;
    var w = side * 1.0;
    var h = side * 1.2;
    var d = side * 0.8;
    var eff = boxType === 'ported' ? '+3 dB vs sealed' : 'Reference';
    document.getElementById('boxVolume').textContent = fmt(vol, 1) + ' L (' + fmt(volCuFt, 2) + ' cu ft)';
    document.getElementById('boxDimensions').textContent = fmt(w * 2.54, 1) + '" W × ' + fmt(h * 2.54, 1) + '" H × ' + fmt(d * 2.54, 1) + '" D (internal)';
    document.getElementById('portInfo').textContent = f3Info;
    document.getElementById('efficiency').textContent = eff;

var r1, r2, percept;
    if (mode === 'add') {
      var combined = 10 * Math.log10(Math.pow(10, val1/10) + Math.pow(10, val2/10));
      r1 = fmt(combined, 1) + ' dB combined';
      r2 = 'Difference: ' + fmt(Math.abs(val1 - val2), 1) + ' dB';
      var diff = combined - Math.max(val1, val2);
      percept = '+' + fmt(diff, 1) + ' dB over loudest source';
    } else if (mode === 'power') {
      var dbP = 10 * Math.log10(val1 / (val2 || 0.001));
      r1 = fmt(dbP, 2) + ' dB';
      r2 = fmt(val1, 3) + 'W vs ' + fmt(val2, 3) + 'W reference';
      percept = dbP >= 10 ? 'Perceived as ~' + fmt(Math.pow(2, dbP/10), 1) + '× louder' : 'Moderate difference';
    } else if (mode === 'voltage') {
      var dbV = 20 * Math.log10(val1 / (val2 || 0.001));
      r1 = fmt(dbV, 2) + ' dB';
      r2 = fmt(val1, 3) + 'V vs ' + fmt(val2, 3) + 'V reference';
      percept = 'Voltage ratio: ' + fmt(val1/val2, 2) + ':1';
    } else {
      var dbAtDist = val1 - 20 * Math.log10(distance / (val2 || 1));
      r1 = fmt(dbAtDist, 1) + ' dB at ' + fmt(distance, 1) + 'm';
      r2 = 'Source: ' + fmt(val1, 0) + ' dB at ' + fmt(val2, 1) + 'm';
      percept = 'Drops ' + fmt(val1 - dbAtDist, 1) + ' dB over distance';
    }
    document.getElementById('result1').textContent = r1;
    document.getElementById('result2').textContent = r2;
    document.getElementById('perception').textContent = percept;

var vol = roomLength * roomWidth * roomHeight;
    var avgAlpha = parseFloat(roomType);
    var surfArea = 2 * (roomLength * roomWidth + roomLength * roomHeight + roomWidth * roomHeight);
    var totalAbs = surfArea * avgAlpha;
    var rt60 = 0.049 * vol / totalAbs;
    var idealRT = 0.3 + 0.002 * Math.pow(vol, 0.5);
    document.getElementById('rt60').textContent = fmt(rt60, 2) + ' seconds';
    document.getElementById('roomVolume').textContent = fmt(vol, 0) + ' cu ft (' + fmt(vol * 0.0283, 0) + ' m³)';
    document.getElementById('totalAbsorption').textContent = fmt(totalAbs, 0) + ' sabins';
    document.getElementById('ideal').textContent = fmt(idealRT, 2) + 's (music studio) / ' + fmt(idealRT * 0.6, 2) + 's (speech)';

var awg = parseInt(gauge);
    var resistancePerFt = {12: 0.00162, 14: 0.00258, 16: 0.00409, 18: 0.00651, 22: 0.0165, 24: 0.0262};
    var rPerFt = resistancePerFt[awg] || 0.00651;
    var totalR = rPerFt * length * 2;
    var maxLen, loss, pwrLoss;
    if (cableType === 'balanced') {
      maxLen = 1000;
      loss = length * 0.01;
      pwrLoss = 'N/A (line level)';
    } else if (cableType === 'unbalanced') {
      maxLen = 25;
      loss = length * 0.05;
      pwrLoss = 'N/A (line level)';
    } else if (cableType === 'speaker') {
      maxLen = impedance / (rPerFt * 2 * 0.05);
      loss = (totalR / (totalR + impedance)) * 100;
      var dampingFactor = impedance / totalR;
      pwrLoss = fmt(loss, 2) + '% (Damping factor: ' + fmt(dampingFactor, 0) + ')';
    } else {
      maxLen = 30;
      loss = length > 30 ? 'Risk of data errors' : 0;
      pwrLoss = 'N/A (digital)';
    }
    document.getElementById('signalLoss').textContent = typeof loss === 'string' ? loss : fmt(loss, 2) + ' dB';
    document.getElementById('maxRecommended').textContent = fmt(maxLen, 0) + ' feet';
    document.getElementById('resistance').textContent = fmt(totalR, 3) + ' ohms';
    document.getElementById('powerLoss').textContent = pwrLoss;

var f = crossoverFreq;
    var z = impedance;
    var ord = parseInt(order);
    var pi = Math.PI;
    var lpC, lpL, hpC, hpL;
    if (ord === 1) {
      lpC = 1 / (2 * pi * f * z);
      lpL = z / (2 * pi * f);
      hpC = lpC;
      hpL = lpL;
    } else if (ord === 2) {
      lpC = Math.sqrt(2) / (4 * pi * f * z);
      lpL = (z * Math.sqrt(2)) / (2 * pi * f);
      hpC = 1 / (Math.sqrt(2) * pi * f * z);
      hpL = z / (Math.sqrt(2) * pi * f);
    } else {
      lpC = 2 / (3 * 2 * pi * f * z);
      lpL = 3 * z / (4 * 2 * pi * f);
      hpC = 1 / (3 * 2 * pi * f * z * 0.5);
      hpL = z / (2 * pi * f * 0.75);
    }
    var uf = function(c) { var v = c * 1e6; return v >= 1 ? fmt(v, 1) + ' µF' : fmt(v * 1000, 1) + ' nF'; };
    var mh = function(l) { var v = l * 1000; return fmt(v, 2) + ' mH'; };
    document.getElementById('lpCap').textContent = uf(lpC);
    document.getElementById('lpInd').textContent = mh(lpL);
    document.getElementById('hpCap').textContent = uf(hpC);
    document.getElementById('hpInd').textContent = mh(hpL);

var beatMs = 60000 / bpm;
    var noteVal = parseFloat(noteType);
    var mod = parseFloat(modifier);
    var ms = beatMs * noteVal * mod;
    var sec = ms / 1000;
    var freq = 1000 / ms;
    var quarter = beatMs;
    var eighth = quarter / 2;
    var sixteenth = quarter / 4;
    document.getElementById('msResult').textContent = fmt(ms, 1) + ' ms';
    document.getElementById('secondsResult').textContent = fmt(sec, 3) + ' s';
    document.getElementById('freqResult').textContent = fmt(freq, 2) + ' Hz';
    document.getElementById('allNotes').textContent = '1/4: ' + fmt(quarter, 0) + 'ms | 1/8: ' + fmt(eighth, 0) + 'ms | 1/16: ' + fmt(sixteenth, 0) + 'ms | 1/8d: ' + fmt(eighth * 1.5, 0) + 'ms | 1/8t: ' + fmt(eighth * 0.667, 0) + 'ms';

var sr = parseInt(sampleRate);
    var bd = parseInt(bitDepth);
    var ch = parseInt(channels);
    var bytesPerSec = sr * (bd / 8) * ch;
    var wavBytes = bytesPerSec * duration;
    var wavMB = wavBytes / (1024 * 1024);
    var flacMB = wavMB * 0.55;
    var mp3MB = (320 * 1000 / 8) * duration / (1024 * 1024) * (ch > 1 ? 1 : 0.5);
    var bitrateKbps = bytesPerSec * 8 / 1000;
    var mins = Math.floor(duration / 60);
    var secs = duration % 60;
    document.getElementById('wavSize').textContent = fmt(wavMB, 1) + ' MB';
    document.getElementById('flacSize').textContent = fmt(flacMB, 1) + ' MB (~55% of WAV)';
    document.getElementById('mp3Size').textContent = fmt(mp3MB, 1) + ' MB';
    document.getElementById('bitrate').textContent = fmt(bitrateKbps, 0) + ' kbps (' + fmt(bitrateKbps / 1000, 1) + ' Mbps)';

var afterBuyFee = amount * (1 - buyFee / 100);
    var coins = afterBuyFee / buyPrice;
    var grossValue = coins * sellPrice;
    var afterSellFee = grossValue * (1 - sellFee / 100);
    var profit = afterSellFee - amount;
    var roi = (profit / amount) * 100;
    document.getElementById('coinsOwned').textContent = coins.toFixed(8);
    document.getElementById('currentValue').textContent = dollar(afterSellFee);
    document.getElementById('profitLoss').textContent = (profit >= 0 ? '+' : '') + dollar(profit);
    document.getElementById('roi').textContent = (roi >= 0 ? '+' : '') + fmt(roi, 2) + '%';

var dailyCoins = hashrate * coinPerDay;
    var revenue = dailyCoins * coinPrice;
    var dailyKWH = (power / 1000) * 24;
    var dailyElec = dailyKWH * electricRate;
    var dailyProf = revenue - dailyElec;
    var monthlyProf = dailyProf * 30;
    var breakDays = dailyProf > 0 ? hardwareCost / dailyProf : Infinity;
    var breakStr = breakDays === Infinity ? 'Never (unprofitable)' : fmt(breakDays, 0) + ' days (' + fmt(breakDays / 30, 1) + ' months)';
    document.getElementById('dailyRevenue').textContent = dollar(revenue);
    document.getElementById('dailyElectricity').textContent = dollar(dailyElec);
    document.getElementById('dailyProfit').textContent = (dailyProf >= 0 ? '+' : '') + dollar(dailyProf);
    document.getElementById('monthlyProfit').textContent = (monthlyProf >= 0 ? '+' : '') + dollar(monthlyProf);
    document.getElementById('breakeven').textContent = breakStr;

var n = parseInt(compoundFreq);
    var years = duration / 12;
    var rate = apy / 100;
    var finalVal = principal * Math.pow(1 + rate / n, n * years);
    var earnings = finalVal - principal;
    var effectiveRate = (Math.pow(finalVal / principal, 1 / years) - 1) * 100;
    var ilLoss = finalVal * (impLoss / 100);
    var afterILVal = finalVal - ilLoss;
    document.getElementById('finalValue').textContent = dollar(finalVal);
    document.getElementById('totalEarnings').textContent = dollar(earnings);
    document.getElementById('effectiveAPY').textContent = fmt(effectiveRate, 2) + '%';
    document.getElementById('afterIL').textContent = impLoss > 0 ? dollar(afterILVal) + ' (-' + dollar(ilLoss) + ' IL)' : 'No IL risk (single-sided staking)';

var gain = salePrice - purchasePrice;
    var rate;
    if (holdingPeriod === 'short') {
      rate = parseInt(taxBracket);
    } else {
      var bracket = parseInt(taxBracket);
      if (bracket <= 12) rate = 0;
      else if (bracket <= 35) rate = 15;
      else rate = 20;
    }
    var tax = Math.max(0, gain * rate / 100);
    var netProfit = gain - tax;
    document.getElementById('capitalGain').textContent = (gain >= 0 ? '+' : '') + dollar(gain);
    document.getElementById('taxRate').textContent = rate + '% (' + holdingPeriod + '-term)';
    document.getElementById('taxOwed').textContent = dollar(tax);
    document.getElementById('netProfit').textContent = dollar(netProfit);

var totalInv = monthlyAmount * months;
    var volFactor = volatility === 'low' ? 0.1 : volatility === 'medium' ? 0.25 : 0.5;
    var totalCoins = 0;
    var midPrice = (startPrice + endPrice) / 2;
    for (var i = 0; i < months; i++) {
      var progress = i / (months - 1 || 1);
      var price = startPrice + (endPrice - startPrice) * progress;
      var wobble = Math.sin(progress * Math.PI * 4) * volFactor * midPrice;
      var monthPrice = Math.max(price + wobble, startPrice * 0.1);
      totalCoins += monthlyAmount / monthPrice;
    }
    var avgPrice = totalInv / totalCoins;
    var dcaVal = totalCoins * endPrice;
    var lumpCoins = totalInv / startPrice;
    var lumpVal = lumpCoins * endPrice;
    var dcaReturn = ((dcaVal - totalInv) / totalInv) * 100;
    document.getElementById('totalInvested').textContent = dollar(totalInv);
    document.getElementById('avgPrice').textContent = dollar(avgPrice);
    document.getElementById('dcaValue').textContent = dollar(dcaVal);
    document.getElementById('lumpValue').textContent = dollar(lumpVal);
    document.getElementById('dcaReturn').textContent = (dcaReturn >= 0 ? '+' : '') + fmt(dcaReturn, 1) + '%';

var limit = parseInt(gasLimit);
    var totalGwei = (gasPrice + priorityFee) * limit;
    var ethCost = totalGwei / 1e9;
    var usdCost = ethCost * ethPrice;
    var baseFeeUSD = (gasPrice * limit / 1e9) * ethPrice;
    var tipUSD = (priorityFee * limit / 1e9) * ethPrice;
    document.getElementById('totalGwei').textContent = fmt(totalGwei, 0) + ' Gwei';
    document.getElementById('ethCost').textContent = ethCost.toFixed(6) + ' ETH';
    document.getElementById('usdCost').textContent = dollar(usdCost);
    document.getElementById('comparison').textContent = 'Base: ' + dollar(baseFeeUSD) + ' + Tip: ' + dollar(tipUSD);
